/// <summary>
///  Freezes the form fields by updating the design when the data source is activated.
/// </summary>
internal final class ETGDMSIntegrationFormDesignHelper
{
}

Method.Source:
public static void updateDesignDMS(FormDataSource formDS)
{
    if(ETGACFParameters::find().EnableDMSIntegration == NoYes::Yes)
    {
        ETGDMSMasterTableMapping dmsMappingTable;
        Common         common   = formDS.cursor();

        TableId tableId = common.TableId;

        TableName tableName = tableId2Name(tableId);
        while select RecId, FieldName from dmsMappingTable
        where dmsMappingTable.TableName == tableName
         && dmsMappingTable.IsActive == NoYes::Yes
        {
            if(dmsMappingTable.RecId)
            {
                formDS.object(fieldName2Id(tableId, dmsMappingTable.FieldName)).allowEdit(false);
            }
        }
    }
}
